{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "결정사항_확정": [
      {
        "topic": "공개 릴리스 목표 시각",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST에 공개 릴리스",
        "condition": "스모크 테스트 통과 필수",
        "certainty": "확정"
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "불일치 발생 시 먼저 패키지 설정(계약) 점검, 계약이 잘못된 경우에만 smoke-theme-pack.mjs 검토",
        "certainty": "확정"
      }
    ],
    "비결정사항": {
      "반려된_제안": [
        {
          "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
          "result": "반려"
        }
      ],
      "내부_스트레치_목표": [
        {
          "item": "수요일 릴리스 제안",
          "scope": "내부 스트레치 목표",
          "note": "공개 릴리스 확정안 아님"
        }
      ],
      "미확정_항목": [
        {
          "item": "README 설치 단계 목요일 검토",
          "note": "가능하면 진행, 담당자 미배정"
        }
      ]
    },
    "risks": [
      {
        "risk": "tarball 경로 오류",
        "impact": "릴리스 지연 가능"
      },
      {
        "risk": "README 설치 단계 최신성 부족",
        "impact": "릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정됨(진행 상태 미보고)",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "확정됨(진행 상태 미보고)",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "명시된 정확 시한 없음(선행조건: Minjun 결과 공유)",
      "status": "확정됨(기한 미정)",
      "source_certainty": "high"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토",
      "due": "목요일(가능하면)",
      "status": "미확정(담당자 미배정)",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 이후 Minjun의 스모크 결과 수신 여부 확인",
      "금요일 12:00 KST 이후 Doyun의 action_items.md 트리아지 노트 작성 여부 확인",
      "스모크 결과 공유 직후 Hara의 tarball 경로 점검 결과 기록",
      "README 설치 단계 검토 담당자 지정 필요 여부 결정",
      "최종 릴리스 승인 권한자 및 릴리스 노트에 수요일 스트레치 목표 기재 여부 결정"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 담당자, 미지정 마감시한의 임의 확정"
    ]
  },
  "non_invention_rules": [
    "명시된 사실만 기록하고 추정 사실을 추가하지 않는다.",
    "확정/반려/미확정 상태를 분리해 표기한다.",
    "조건부 결정은 조건(예: 스모크 통과)을 함께 유지한다.",
    "담당자 또는 마감이 없는 항목은 null 또는 미정으로 유지한다.",
    "명시적 비사실(고객, 예산, 보안, 장애, 법무)은 어떤 형태로도 생성하지 않는다."
  ]
}
